        var Translator = new Translate({"Please select an option.":"\u0641\u0636\u0644\u0627 \u0627\u062e\u062a\u0631 \u062e\u064a\u0627\u0631 .","This is a required field.":"\u0647\u0630\u0627 \u0627\u0644\u062d\u0642\u0644 \u0645\u0637\u0644\u0648\u0628.","Please enter a valid number in this field.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0642\u0645 \u0628\u0625\u062f\u062e\u0627\u0644 \u0631\u0642\u0645 \u0635\u062d\u064a\u062d \u0641\u064a \u0647\u0630\u0627 \u0627\u0644\u062d\u0642\u0644.","Please use letters only (a-z or A-Z) in this field.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u062d\u0631\u0648\u0641 \u0645\u0646 (\u0627\u0644\u0623\u0644\u0641 \u0627\u0644\u0649 \u0627\u0644\u064a\u0627\u0621) \u0641\u064a \u0647\u0630\u0627 \u0627\u0644\u062d\u0642\u0644","Please use only letters (a-z), numbers (0-9) or underscore(_) in this field, first character should be a letter.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062d\u0631\u0648\u0641 (\u0645\u0646 \u0627\u0644\u0627\u0644\u0641 \u0627\u0644\u0649 \u0627\u0644\u064a\u0627\u0621 \u0627\u0644\u0627\u0642\u0627\u0645\u0629) \u060c \u0627\u0631\u0642\u0627\u0645 (0-9) \u064a\u0624\u0643\u062f \u0627\u0648 (_) \u0641\u064a \u0647\u0630\u0627 \u0627\u0644\u0645\u062c\u0627\u0644 \u060c \u064a\u0646\u0628\u063a\u064a \u0627\u0646 \u064a\u0643\u0648\u0646 \u0627\u0644\u062d\u0631\u0641 \u0627\u0644\u0627\u0648\u0644 \u0631\u0633\u0627\u0644\u0629.","Please enter a valid phone number. For example (123) 456-7890 or 123-456-7890.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0642\u0645 \u0628\u0625\u062f\u062e\u0627\u0644 \u0631\u0642\u0645 \u0647\u0627\u062a\u0641 \u0635\u062d\u064a\u062d. \u0643\u0645\u062b\u0627\u0644 (123) 456-7890 \u0623\u0648 123-456-7890.","Please enter a valid date.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0642\u0645 \u0628\u0625\u062f\u062e\u0627\u0644 \u062a\u0627\u0631\u064a\u062e \u0635\u062d\u064a\u062d.","Please enter a valid email address. For example johndoe@domain.com.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0642\u0645 \u0628\u0625\u062f\u062e\u0627\u0644 \u0628\u0631\u064a\u062f \u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a \u0635\u062d\u064a\u062d. \u0643\u0645\u062b\u0627\u0644 johndoe@domain.com.","Please enter 6 or more characters. Leading or trailing spaces will be ignored.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0642\u0645 \u0628\u0625\u062f\u062e\u0627\u0644 6 \u0623\u062d\u0631\u0641 \u0623\u0648 \u0623\u0643\u062b\u0631. \u0633\u064a\u062a\u0645 \u062a\u062c\u0627\u0647\u0644 \u0627\u0644\u0645\u0633\u0627\u0641\u0627\u062a \u0642\u0628\u0644 \u0623\u0648 \u0628\u0639\u062f \u0627\u0644\u0623\u062d\u0631\u0641.","Please make sure your passwords match.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u062a\u0623\u0643\u062f \u0645\u0646 \u062a\u0637\u0627\u0628\u0642 \u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631.","Please enter a valid URL. For example http:\/\/www.example.com or www.example.com":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0627\u062f\u062e\u0627\u0644 \u0639\u0646\u0648\u0627\u0646. \u0641\u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644 http:\/\/www.example.com \u0627\u0648 www.example.com","Please enter a valid social security number. For example 123-45-6789.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0627\u062f\u062e\u0627\u0644 \u0631\u0642\u0645 \u0627\u0644\u0636\u0645\u0627\u0646 \u0627\u0644\u0627\u062c\u062a\u0645\u0627\u0639\u064a. \u0641\u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644 123-45-6789.","Please enter a valid zip code. For example 90602 or 90602-1234.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0625\u062f\u062e\u0627\u0644 \u0627\u0644\u0631\u0645\u0632 \u0627\u0644\u0628\u0631\u064a\u062f\u064a. \u0641\u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644 90602 \u0627\u0648 90602-1234.","Please enter a valid zip code.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0625\u062f\u062e\u0627\u0644 \u0627\u0644\u0631\u0645\u0632 \u0627\u0644\u0628\u0631\u064a\u062f\u064a.","Please use this date format: dd\/mm\/yyyy. For example 17\/03\/2006 for the 17th of March, 2006.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0647\u0630\u0627 \u0627\u0644\u0634\u0643\u0644 \u062d\u062a\u0649 \u0627\u0644\u0622\u0646 : \u0627\u0644\u064a\u0648\u0645 \/ \u0627\u0644\u0634\u0647\u0631 \/ \u0627\u0644\u0633\u0646\u0629. \u0641\u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644 17\/03\/2006 \u0644\u0644\u0627\u0644\u0633\u0627\u0628\u0639 \u0639\u0634\u0631 \u0645\u0646 \u0627\u0630\u0627\u0631 \/ \u0645\u0627\u0631\u0633 \u060c 2006.","Please enter a valid $ amount. For example $100.00.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u0627\u062f\u062e\u0627\u0644 \u062f\u0648\u0644\u0627\u0631 \u0645\u0646 \u0627\u0644\u0645\u0628\u0644\u063a. \u0641\u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644 100\u060c00 \u062f\u0648\u0644\u0627\u0631..","Please select one of the above options.":"\u0641\u0636\u0644\u0627 \u0627\u062e\u062a\u0627\u0631 \u0645\u0646 \u0627\u0644\u062e\u064a\u0627\u0631\u0627\u062a \u0627\u0644\u0645\u0648\u062c\u0648\u062f\u0647 \u0641\u064a \u0627\u0644\u0627\u0639\u0644\u0649.","Please select one of the options.":"\u0641\u0636\u0644\u0627 \u0627\u062e\u062a\u0627\u0631 \u0648\u0627\u062d\u062f \u0645\u0646 \u0627\u0644\u062e\u064a\u0627\u0631\u0627\u062a.","Please select State\/Province.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0627\u062e\u062a\u0631 \u0648\u0644\u0627\u064a\u0629\/\u0645\u0642\u0627\u0637\u0639\u0629.","Please enter a number greater than 0 in this field.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0642\u0645 \u0628\u0625\u062f\u062e\u0627\u0644 \u0631\u0642\u0645 \u0623\u0643\u0628\u0631 \u0645\u0646 0 \u0641\u064a \u0647\u0630\u0627 \u0627\u0644\u062d\u0642\u0644.","Please enter a valid credit card number.":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0642\u0645 \u0628\u0625\u062f\u062e\u0627\u0644 \u0631\u0642\u0645 \u0628\u0637\u0627\u0642\u0629 \u0625\u0626\u062a\u0645\u0627\u0646 \u0635\u062d\u064a\u062d.","Please wait, loading...":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0627\u0646\u062a\u0638\u0631\u060c \u062c\u0627\u0631 \u0627\u0644\u062a\u062d\u0645\u064a\u0644...","Complete":"\u062a\u0643\u0645\u0644\u0629","Please choose to register or to checkout as a guest":"\u0645\u0646 \u0641\u0636\u0644\u0643 \u0627\u062e\u062a\u0631 \u0627\u0644\u062a\u0633\u062c\u064a\u0644 \u0627\u0648 \u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u062e\u0631\u0648\u062c \u0643\u0636\u064a\u0641","Please specify payment method.":"\u0627\u0644\u0631\u062c\u0627\u0621 \u062a\u062d\u062f\u064a\u062f \u0637\u0631\u064a\u0642\u0629 \u0627\u0644\u062f\u0641\u0639"});
